  en: { 'קל': 'Easy', 'בינוני': 'Medium', 'קשה': 'Hard', 'מומחה': 'Expert' },
  ar: { 'קל': 'سهل', 'בינוני': 'متوسط', 'קשה': 'صعب', 'מומחה': 'خبير' },
  ru: { 'קל': 'Легкий', 'בינוני': 'Средний', 'קשה': 'Сложный', 'מומחה': 'Эксперт' },
